// api/restaurants.js
// Función serverless de Vercel que expone el CRUD de restaurantes.
// Los datos viven en un Hash de Upstash Redis (misma base de datos que usa api/feedback.js).
//
// Variables de entorno necesarias:
//   KV_REST_API_URL, KV_REST_API_TOKEN  (inyectadas por la integración de Upstash en Vercel)
//   EDITOR_USER, EDITOR_PASS            (las mismas credenciales del modo edición de la web)
//
// Rutas:
//   GET    /api/restaurants          -> lista completa (público, sin auth). Siembra automáticamente
//                                        la base de datos la primera vez que se llama, si está vacía.
//   POST   /api/restaurants          -> crea un restaurante nuevo (requiere auth)
//   PUT    /api/restaurants          -> actualiza uno existente por id (requiere auth)
//   DELETE /api/restaurants?id=XXX   -> elimina uno por id (requiere auth)

const HASH_KEY = 'lalistadelgloton:restaurants';
const DEFAULT_LAT = 40.4168;
const DEFAULT_LNG = -3.7038;

