/* ============ Helpers Redis (Upstash REST) ============ */
function getEnv(name) {
  return process.env[name];
}

async function redisRequest(command) {
  const url = getEnv('KV_REST_API_URL');
  const token = getEnv('KV_REST_API_TOKEN');
  if (!url || !token) {
    throw new Error('Faltan las variables de entorno de Upstash (KV_REST_API_URL / KV_REST_API_TOKEN)');
  }
  const res = await fetch(url, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(command),
  });
  if (!res.ok) {
    const text = await res.text();
    throw new Error(`Upstash error ${res.status}: ${text}`);
  }
  return res.json();
}

async function redisPipeline(commands) {
  const url = getEnv('KV_REST_API_URL');
  const token = getEnv('KV_REST_API_TOKEN');
  if (!url || !token) {
    throw new Error('Faltan las variables de entorno de Upstash (KV_REST_API_URL / KV_REST_API_TOKEN)');
  }
  const res = await fetch(`${url}/pipeline`, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(commands),
  });
  if (!res.ok) {
    const text = await res.text();
    throw new Error(`Upstash pipeline error ${res.status}: ${text}`);
  }
  return res.json();
}

function parseHashResult(result) {
  // Upstash puede devolver el HGETALL como array plano [campo, valor, campo, valor, ...]
  // o, según el cliente, como objeto {campo: valor, ...}. Cubrimos ambos casos.
  if (!result) return [];
  if (Array.isArray(result)) {
    const items = [];
    for (let i = 0; i < result.length; i += 2) {
      const raw = result[i + 1];
      try {
        items.push(JSON.parse(raw));
      } catch (e) {
        // ignorar entradas corruptas
      }
    }
    return items;
  }
  if (typeof result === 'object') {
    return Object.values(result)
      .map((raw) => {
        try {
          return JSON.parse(raw);
        } catch (e) {
          return null;
        }
      })
      .filter(Boolean);
  }
  return [];
}

/* ============ Autenticación (Basic Auth, mismas credenciales que feedback.js) ============ */
function isAuthorized(req) {
  const user = getEnv('EDITOR_USER');
  const pass = getEnv('EDITOR_PASS');
  if (!user || !pass) return false;
  const header = req.headers['authorization'] || '';
  const [scheme, encoded] = header.split(' ');
  if (scheme !== 'Basic' || !encoded) return false;
  const decoded = Buffer.from(encoded, 'base64').toString('utf-8');
  const sepIndex = decoded.indexOf(':');
  if (sepIndex === -1) return false;
  const reqUser = decoded.slice(0, sepIndex);
  const reqPass = decoded.slice(sepIndex + 1);
  return reqUser === user && reqPass === pass;
}

/* ============ Siembra inicial ============ */
async function ensureSeeded() {
  const hlenResult = await redisRequest(['HLEN', HASH_KEY]);
  const count = (hlenResult && hlenResult.result) || 0;
  if (count > 0) return;

  const commands = SEED_DATA.map((item) => ['HSET', HASH_KEY, item.id, JSON.stringify(item)]);
  const batchSize = 50;
  for (let i = 0; i < commands.length; i += batchSize) {
    await redisPipeline(commands.slice(i, i + batchSize));
  }
}

function normalizeItem(id, body, existing) {
  const src = existing || {};
  const pick = (key, fallback) =>
    body[key] !== undefined && body[key] !== null ? String(body[key]) : (src[key] || fallback || '');
  return {
    id,
    cat: pick('cat', ''),
    name: pick('name', ''),
    price: pick('price', ''),
    cuisine: pick('cuisine', ''),
    zone: pick('zone', ''),
    highlight: pick('highlight', ''),
    desc: pick('desc', ''),
    lat: typeof body.lat === 'number' ? body.lat : typeof src.lat === 'number' ? src.lat : DEFAULT_LAT,
    lng: typeof body.lng === 'number' ? body.lng : typeof src.lng === 'number' ? src.lng : DEFAULT_LNG,
  };
}

/* ============ Handler ============ */
export default async function handler(req, res) {
  try {
    if (req.method === 'GET') {
      await ensureSeeded();
      const result = await redisRequest(['HGETALL', HASH_KEY]);
      const items = parseHashResult(result && result.result);
      // Orden estable: por categoría y luego nombre, para que la primera carga sea consistente
      items.sort((a, b) => {
        if (a.cat !== b.cat) return (a.cat || '').localeCompare(b.cat || '', 'es');
        return (a.name || '').localeCompare(b.name || '', 'es');
      });
      return res.status(200).json(items);
    }

    // Todas las mutaciones requieren autenticación
    if (!isAuthorized(req)) {
      res.setHeader('WWW-Authenticate', 'Basic realm="Editor"');
      return res.status(401).json({ error: 'No autorizado' });
    }

    if (req.method === 'POST') {
      const body = req.body || {};
      if (!body.name || !String(body.name).trim()) {
        return res.status(400).json({ error: 'Falta el nombre del restaurante' });
      }
      const id = 'r_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8);
      const item = normalizeItem(id, body, null);
      await redisRequest(['HSET', HASH_KEY, id, JSON.stringify(item)]);
      return res.status(200).json(item);
    }

    if (req.method === 'PUT') {
      const body = req.body || {};
      if (!body.id) {
        return res.status(400).json({ error: 'Falta el id del restaurante' });
      }
      const existingRaw = await redisRequest(['HGET', HASH_KEY, body.id]);
      let existing = null;
      if (existingRaw && existingRaw.result) {
        try {
          existing = JSON.parse(existingRaw.result);
        } catch (e) {
          existing = null;
        }
      }
      const item = normalizeItem(body.id, body, existing);
      await redisRequest(['HSET', HASH_KEY, body.id, JSON.stringify(item)]);
      return res.status(200).json(item);
    }

    if (req.method === 'DELETE') {
      const id = (req.query && req.query.id) || (req.body && req.body.id);
      if (!id) {
        return res.status(400).json({ error: 'Falta el id del restaurante' });
      }
      await redisRequest(['HDEL', HASH_KEY, id]);
      return res.status(200).json({ ok: true });
    }

    res.setHeader('Allow', 'GET, POST, PUT, DELETE');
    return res.status(405).json({ error: 'Método no permitido' });
  } catch (err) {
    console.error('Error en /api/restaurants:', err);
    return res.status(500).json({ error: 'Error inesperado en el servidor' });
  }
}
